content.query:
AppPageViews
| where TimeGenerated {TimeRange}
| summarize visitors = dcount(UserId)

AppPageViews
| where TimeGenerated {TimeRange}
| summarize sessions = dcount(SessionId)

AppPageViews
| where TimeGenerated {TimeRange}
| summarize page_views = sum(ItemCount)

let totalSessions = toscalar(AppPageViews
| where TimeGenerated {TimeRange}
| summarize dcount(SessionId));
let scanSessions = toscalar(AppEvents
| where TimeGenerated {TimeRange}
| where Name == "scan_requested_client"
| summarize dcount(SessionId));
print session_to_scan_rate_pct = round(iff(totalSessions == 0, 0.0, todouble(scanSessions) * 100.0 / todouble(totalSessions)), 1)

let requested = toscalar(AppEvents
| where TimeGenerated {TimeRange}
| where Name == "report_share_requested_client"
| summarize sum(ItemCount));
let completed = toscalar(AppEvents
| where TimeGenerated {TimeRange}
| where Name == "report_shared_client"
| summarize sum(ItemCount));
print share_completion_rate_pct = round(iff(requested == 0, 0.0, todouble(completed) * 100.0 / todouble(requested)), 1)

let repoFilter = "{RepoFilter}";
let pageSessions = toscalar(AppPageViews
| where TimeGenerated {TimeRange}
| summarize dcount(SessionId));
let scanSessions = toscalar(AppEvents
| where TimeGenerated {TimeRange}
| where Name == "scan_requested_client"
| summarize dcount(SessionId));
let completedScans = toscalar(AppEvents
| where TimeGenerated {TimeRange}
| where Name == "scan_completed"
| extend repo_name = tostring(Properties.repo_name)
| where repoFilter == "*" or repo_name == repoFilter
| summarize sum(ItemCount));
let reportsCreated = toscalar(AppEvents
| where TimeGenerated {TimeRange}
| where Name == "report_created"
| extend repo_name = tostring(Properties.repo_name)
| where repoFilter == "*" or repo_name == repoFilter
| summarize sum(ItemCount));
let reportViews = toscalar(AppEvents
| where TimeGenerated {TimeRange}
| where Name == "shared_report_viewed"
| extend repo_name = tostring(Properties.repo_name)
| where repoFilter == "*" or repo_name == repoFilter
| summarize sum(ItemCount));
datatable(Step:string, Count:long)
[
  "Sessions", tolong(pageSessions),
  "Scan sessions", tolong(scanSessions),
  "Completed scans", tolong(completedScans),
  "Reports created", tolong(reportsCreated),
  "Shared report views", tolong(reportViews)
]
| serialize StepNumber = row_number()
| extend StepConversionPct = round(iff(StepNumber == 1, 100.0, todouble(Count) * 100.0 / todouble(prev(Count))), 1)
| extend OverallConversionPct = round(iff(pageSessions == 0, 0.0, todouble(Count) * 100.0 / todouble(pageSessions)), 1)
